import com.ingenico.telium.payment.*;
import com.ingenico.telium.crypto.*;
import com.ingenico.security.p2pe.*;
import javax.crypto.SecretKey;
import java.security.KeyStore;
import java.util.logging.Logger;

/**
 * P2PE-compliant payment terminal integration
 * Card data is encrypted in hardware, never exposed in application memory
 */
public class SecurePaymentTerminal {
    private static final Logger logger = Logger.getLogger(SecurePaymentTerminal.class.getName());
    private final P2PECryptoService cryptoService;
    private final String merchantId;
    private final KeyStore terminalKeyStore;

    public SecurePaymentTerminal(String merchantId, KeyStore keyStore) {
        this.merchantId = merchantId;
        this.terminalKeyStore = keyStore;
        this.cryptoService = P2PECryptoService.getInstance();
    }

    /**
     * Process payment with P2PE - card data never in memory unencrypted
     * @param amount Transaction amount in cents
     * @return Encrypted payment token (no PAN exposure)
     */
    public EncryptedPaymentResponse processPayment(long amount) {
        try {
            // Initialize payment terminal with P2PE mode
            PaymentTerminal terminal = new PaymentTerminal();
            terminal.setEncryptionMode(EncryptionMode.P2PE_DUKPT);

            // Configure terminal to encrypt in hardware (SRED - Secure Reading and Exchange of Data)
            TerminalConfig config = new TerminalConfig.Builder()
                .enableP2PE(true)
                .setEncryptionAlgorithm("AES-256")
                .setKeyManagementScheme("DUKPT") // Derived Unique Key Per Transaction
                .setMerchantId(merchantId)
                .build();

            terminal.configure(config);

            // Prompt for card - data encrypted by terminal hardware before entering system RAM
            logger.info("Waiting for card presentation...");
            CardPresentationRequest request = new CardPresentationRequest.Builder()
                .setAmount(amount)
                .setCurrency("USD")
                .setTransactionType(TransactionType.SALE)
                .setPrompt("Insert, Swipe, or Tap Card")
                .setTimeout(30000) // 30 second timeout
                .build();

            // CRITICAL: This returns ENCRYPTED data only - PAN never in memory
            // Track 1/Track 2 data encrypted in terminal hardware using injected DUKPT key
            CardPresentationResult result = terminal.presentCard(request);

            if (result.getStatus() != CardStatus.SUCCESS) {
                throw new PaymentException("Card read failed: " + result.getStatusMessage());
            }

            // Get encrypted card data - this is a cryptogram, not plaintext PAN
            EncryptedCardData encryptedData = result.getEncryptedCardData();

            // IMPORTANT: Never log, store, or process plaintext card data
            // Only work with encrypted payloads and tokens

            // Build encrypted payment request for processor
            EncryptedPaymentRequest paymentRequest = EncryptedPaymentRequest.builder()
                .merchantId(merchantId)
                .amount(amount)
                .currency("USD")
                // Encrypted Track 1/Track 2 data (AES-256 encrypted by terminal)
                .encryptedTrackData(encryptedData.getEncryptedTracks())
                // KSN - Key Serial Number for DUKPT key derivation
                .keySerialNumber(encryptedData.getKSN())
                // Device ID for P2PE validation
                .deviceId(encryptedData.getDeviceId())
                // EMV tags if chip transaction (also encrypted)
                .emvData(encryptedData.getEMVTags())
                .build();

            // Send encrypted payment to P2PE-certified processor
            // Processor decrypts in HSM (Hardware Security Module) - never in application
            EncryptedPaymentResponse response = sendToProcessor(paymentRequest);

            // Log transaction with token only (no PAN)
            logger.info(String.format(
                "Transaction approved. Token: %s, Amount: $%.2f, Auth Code: %s",
                response.getPaymentToken(),
                amount / 100.0,
                response.getAuthorizationCode()
            ));

            return response;

        } catch (TerminalException e) {
            logger.severe("Terminal error: " + e.getMessage());
            throw new PaymentException("Payment processing failed", e);
        }
    }

    /**
     * Send encrypted payment to P2PE processor (HSM decryption)
     * @param request Encrypted payment request
     * @return Payment response with token (not PAN)
     */
    private EncryptedPaymentResponse sendToProcessor(EncryptedPaymentRequest request) {
        // Send to P2PE-certified processor like Shift4, Bluefin, TokenEx
        // Processor uses HSM to decrypt and authorize transaction
        // Returns payment token (not PAN) for storage/reconciliation

        ProcessorClient processor = new ProcessorClient(
            "https://api.p2pe-processor.com/v3/authorize",
            terminalKeyStore
        );

        return processor.authorize(request);
    }

    /**
     * Tokenize card for recurring payments (still P2PE encrypted)
     * @param customerId Customer identifier
     * @return Payment token for future use
     */
    public String tokenizeCard(String customerId) {
        // Card data encrypted in terminal hardware
        EncryptedPaymentResponse response = processPayment(0); // $0 auth for tokenization

        // Store token (not PAN) for recurring payments
        String token = response.getPaymentToken();

        // Log tokenization event (no PAN exposure)
        logger.info(String.format(
            "Card tokenized for customer %s. Token: %s (last 4: %s)",
            customerId,
            token,
            response.getLast4Digits()
        ));

        return token;
    }

    /**
     * Verify P2PE terminal compliance
     * @return true if terminal is P2PE-compliant
     */
    public boolean verifyP2PECompliance() {
        try {
            PaymentTerminal terminal = new PaymentTerminal();

            // Verify terminal is P2PE-validated by PCI SSC
            TerminalInfo info = terminal.getTerminalInfo();

            boolean isP2PEValidated = info.isP2PEValidated();
            boolean hasValidCertificate = info.hasValidP2PECertificate();
            boolean sredEnabled = info.isSREDEnabled();

            logger.info(String.format(
                "Terminal P2PE Status - Validated: %s, Certificate Valid: %s, SRED: %s, Device ID: %s",
                isP2PEValidated,
                hasValidCertificate,
                sredEnabled,
                info.getDeviceId()
            ));

            return isP2PEValidated && hasValidCertificate && sredEnabled;

        } catch (TerminalException e) {
            logger.severe("Failed to verify P2PE compliance: " + e.getMessage());
            return false;
        }
    }
}

// Example usage
public class POSApplication {
    public static void main(String[] args) {
        try {
            // Load merchant keystore with terminal certificates
            KeyStore keyStore = KeyStore.getInstance("PKCS12");
            keyStore.load(
                new FileInputStream("/secure/merchant-keystore.p12"),
                "keystorePassword".toCharArray()
            );

            SecurePaymentTerminal terminal = new SecurePaymentTerminal(
                "MERCHANT_123456",
                keyStore
            );

            // Verify terminal is P2PE-compliant before accepting payments
            if (!terminal.verifyP2PECompliance()) {
                System.err.println("FATAL: Terminal is not P2PE-compliant!");
                System.exit(1);
            }

            // Process payment - card data never exposed in memory
            EncryptedPaymentResponse response = terminal.processPayment(4999); // $49.99

            System.out.println("Payment successful!");
            System.out.println("Token: " + response.getPaymentToken());
            System.out.println("Auth Code: " + response.getAuthorizationCode());

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
